baseCreate.query:
mutation CustomerLiveHybridOverlayCreate($input: CustomerInput!) {
  customerCreate(input: $input) {
    customer {
      id
      email
      firstName
      lastName
      displayName
      state
      tags
      defaultEmailAddress {
        emailAddress
      }
      defaultPhoneNumber {
        phoneNumber
      }
    }
    userErrors {
      field
      message
    }
  }
}

duplicateHydrate.query:
query CustomerDuplicateHydrate($query: String!) {
  customers(first: 1, query: $query) {
    nodes { id }
  }
}

baseRead.query:
query CustomerLiveHybridOverlayRead(
  $realId: ID!
  $realEmail: String!
  $stagedEmail: String!
  $missingEmail: String!
  $catalogQuery: String!
  $stagedQuery: String!
) {
  byRealId: customer(id: $realId) {
    id
    email
    displayName
  }
  byRealEmail: customerByIdentifier(identifier: { emailAddress: $realEmail }) {
    id
    email
    displayName
  }
  byStagedEmail: customerByIdentifier(identifier: { emailAddress: $stagedEmail }) {
    id
    email
    displayName
  }
  byMissingEmail: customerByIdentifier(identifier: { emailAddress: $missingEmail }) {
    id
    email
  }
  catalog: customers(first: 10, query: $catalogQuery, sortKey: NAME) {
    nodes {
      id
      email
      displayName
      tags
    }
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
  }
  firstPage: customers(first: 1, query: $catalogQuery, sortKey: NAME) {
    edges {
      cursor
      node {
        id
        email
        displayName
      }
    }
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
  }
  matchingCatalog: customers(first: 10, query: $stagedQuery, sortKey: NAME) {
    nodes {
      id
      email
      displayName
    }
  }
  matchingCount: customersCount(query: $stagedQuery) {
    count
    precision
  }
  totalCount: customersCount {
    count
    precision
  }
}

